+static inline int frozen_in(JSContext *ctx, JSValue key, JSValue obj) {
+    JSAtom atom = JS_ValueToAtom(ctx, key);
+    if (atom == JS_ATOM_NULL) return -1;
+    int r = JS_HasProperty(ctx, obj, atom);
+    JS_FreeAtom(ctx, atom);
+    return r;
+}
